SELECT ?votes
WHERE {
  ?candidate wdt:P4020 ?election.
  ?candidate wdt:P1099 ?win.
  ?election = wd:Q10080.
  ?candidate p:P4020 ?stmt.
  ?stmt ps:P4020 wd:Q10080.
  ?stmt pq:P1760 ?votes.
  FILTER (EXISTS {
    SELECT (COUNT(DISTINCT ?allElection) AS ?count)
    WHERE {
      ?candidate wdt:P4020 ?allElection.
    }
    HAVING (?count = 5)
  })
  FILTER (EXISTS {
    SELECT (COUNT(DISTINCT ?allWin) AS ?count)
    WHERE {
      ?candidate wdt:P1099 ?allWin.
    }
    HAVING (?count = 1)
  })
}

SELECT DISTINCT ?election WHERE {
  ?election wdt:P585 ?date;
           wdt:P31 wd:Q872316;
           wdt:P131 wd:Q16.
  FILTER (year(?date) = 1943)
}

SELECT ?votes
WHERE {
  ?candidate p:P4020 ?stmt.
  ?stmt ps:P4020 wd:Q484736;
    pq:P1760 ?votes.
  ?candidate wdt:P4020 ?all_election.
  ?candidate wdt:P1099 ?all_win.
}
GROUP BY ?candidate ?votes
HAVING (COUNT(DISTINCT ?all_election) = 5 && COUNT(DISTINCT ?all_win) = 1)

